const input = $json;
const invoices = Array.isArray(input.invoices) ? input.invoices : [];
const lowConfidenceThreshold = Number(input.lowConfidenceThreshold ?? 0.8);
const autoApproveBelow = Number(input.autoApproveBelow ?? 0);

const normalize = (value) => String(value ?? '').trim();
const lower = (value) => normalize(value).toLowerCase();
const amount = (value) => Number.isFinite(Number(value)) ? Number(value) : null;
const dateMs = (value) => {
  const ms = Date.parse(value);
  return Number.isFinite(ms) ? ms : null;
};
const duplicateKey = (invoice) => [lower(invoice.vendorName), lower(invoice.invoiceNumber), amount(invoice.total), lower(invoice.currency)].join('|');
const seen = new Map();
const normalized = invoices.map((invoice, index) => {
  const subtotal = amount(invoice.subtotal);
  const tax = amount(invoice.tax) ?? 0;
  const total = amount(invoice.total);
  const confidence = amount(invoice.extractedTextConfidence);
  const issues = [];
  const warnings = [];
  if (!normalize(invoice.vendorName)) issues.push('Missing vendor name');
  if (!normalize(invoice.invoiceNumber)) issues.push('Missing invoice number');
  if (!dateMs(invoice.invoiceDate)) issues.push('Missing or invalid invoice date');
  if (!total || total <= 0) issues.push('Missing or invalid invoice total');
  if (subtotal != null && total != null && Math.abs((subtotal + tax) - total) > 0.05) warnings.push('Subtotal plus tax does not match total');
  if (confidence != null && confidence < lowConfidenceThreshold) issues.push('Low extraction confidence');
  if (!normalize(invoice.poNumber)) warnings.push('Missing purchase order number');
  if (!normalize(invoice.dueDate)) warnings.push('Missing due date');
  const key = duplicateKey(invoice);
  const duplicateOf = seen.get(key);
  if (duplicateOf) issues.push('Possible duplicate invoice');
  else seen.set(key, invoice.id || invoice.invoiceNumber || String(index + 1));
  const riskScore = issues.length * 30 + warnings.length * 10 + (total && total > 1000 ? 20 : 0);
  let reviewStatus = 'ready_for_review';
  if (issues.length > 0) reviewStatus = 'needs_fix';
  else if (total != null && total <= autoApproveBelow) reviewStatus = 'low_value_ready';
  return {
    ...invoice,
    normalizedVendor: normalize(invoice.vendorName),
    normalizedInvoiceNumber: normalize(invoice.invoiceNumber),
    subtotal,
    tax,
    total,
    confidence,
    duplicateKey: key,
    duplicateOf: duplicateOf || null,
    issues,
    warnings,
    riskScore,
    reviewStatus,
    suggestedOwner: input.reviewOwner || 'Finance Ops'
  };
});
return normalized.map((invoice) => ({ json: invoice }));

const invoices = $input.all().map((item) => item.json);
const needsFix = invoices.filter((invoice) => invoice.reviewStatus === 'needs_fix');
const duplicateRisk = invoices.filter((invoice) => invoice.issues?.includes('Possible duplicate invoice'));
const lowConfidence = invoices.filter((invoice) => invoice.issues?.includes('Low extraction confidence'));
const missingPo = invoices.filter((invoice) => invoice.warnings?.includes('Missing purchase order number'));
const ready = invoices.filter((invoice) => invoice.reviewStatus !== 'needs_fix');
const reviewQueue = invoices
  .slice()
  .sort((a, b) => (b.riskScore || 0) - (a.riskScore || 0))
  .map((invoice) => ({
    id: invoice.id,
    vendorName: invoice.vendorName || '(missing vendor)',
    invoiceNumber: invoice.invoiceNumber || '(missing invoice number)',
    total: invoice.total,
    currency: invoice.currency,
    dueDate: invoice.dueDate || null,
    reviewStatus: invoice.reviewStatus,
    riskScore: invoice.riskScore,
    issues: invoice.issues,
    warnings: invoice.warnings,
    duplicateOf: invoice.duplicateOf,
    suggestedOwner: invoice.suggestedOwner,
    attachmentName: invoice.attachmentName
  }));
const approvalCandidates = ready.filter((invoice) => invoice.reviewStatus === 'low_value_ready').map((invoice) => ({
  id: invoice.id,
  vendorName: invoice.vendorName,
  invoiceNumber: invoice.invoiceNumber,
  total: invoice.total,
  currency: invoice.currency,
  note: 'Low value and no blocking issues. Still requires finance policy approval before payment.'
}));
return [{ json: {
  totalInvoices: invoices.length,
  needsFixCount: needsFix.length,
  duplicateRiskCount: duplicateRisk.length,
  lowConfidenceCount: lowConfidence.length,
  missingPoCount: missingPo.length,
  readyCount: ready.length,
  reviewQueue,
  approvalCandidates,
  duplicateRisk,
  lowConfidence,
  missingPo,
  invoices
} }];
